649: 
650:             final CompletableFuture<PendingCheckpoint> pendingCheckpointCompletableFuture =
651:                     checkpointPlanFuture
652:                             .thenApplyAsync(
653:                                     plan -> {
654:                                         try {
655:                                             // this must happen outside the coordinator-wide lock,
656:                                             // because it communicates with external services
657:                                             // (in HA mode) and may block for a while.
658:                                             long checkpointID =
659:                                                     checkpointIdCounter.getAndIncrement();
