661:                                         } catch (Throwable e) {
662:                                             throw new CompletionException(e);
663:                                         }
664:                                     },
665:                                     executor)
666:                             .thenApplyAsync(
667:                                     (checkpointInfo) ->
668:                                             createPendingCheckpoint(
669:                                                     timestamp,
670:                                                     request.props,
671:                                                     checkpointInfo.f0,
672:                                                     request.isPeriodic,
673:                                                     checkpointInfo.f1,
674:                                                     request.getOnCompletionFuture(),
675:                                                     masterTriggerCompletionPromise),
676:                                     timer);
677: 
678:             final CompletableFuture<?> coordinatorCheckpointsComplete =
679:                     pendingCheckpointCompletableFuture
680:                             .thenApplyAsync(
681:                                     pendingCheckpoint -> {
682:                                         try {
683:                                             CheckpointStorageLocation checkpointStorageLocation =
684:                                                     initializeCheckpointLocation(
685:                                                             pendingCheckpoint.getCheckpointID(),
686:                                                             request.props,
