697:                                     (checkpointInfo) -> {
698:                                         PendingCheckpoint pendingCheckpoint = checkpointInfo.f0;
699:                                         if (pendingCheckpoint.isDisposed()) {
700:                                             // The disposed checkpoint will be handled later,
701:                                             // skip snapshotting the coordinator states.
702:                                             return null;
703:                                         }
704:                                         synchronized (lock) {
705:                                             pendingCheckpoint.setCheckpointTargetLocation(
706:                                                     checkpointInfo.f1);
707:                                         }
708:                                         return OperatorCoordinatorCheckpoints
709:                                                 .triggerAndAcknowledgeAllCoordinatorCheckpointsWithCompletion(
710:                                                         coordinatorsToCheckpoint,
711:                                                         pendingCheckpoint,
712:                                                         timer);
713:                                     },
714:                                     timer);
715: 
716:             // We have to take the snapshot of the master hooks after the coordinator checkpoints
717:             // has completed.
718:             // This is to ensure the tasks are checkpointed after the OperatorCoordinators in case
719:             // ExternallyInducedSource is used.
720:             final CompletableFuture<?> masterStatesComplete =
721:                     coordinatorCheckpointsComplete.thenComposeAsync(
722:                             ignored -> {
723:                                 // If the code reaches here, the pending checkpoint is guaranteed to
