732:                                     // The disposed checkpoint will be handled later,
733:                                     // skip snapshotting the master states.
734:                                     return null;
735:                                 }
736:                                 return snapshotMasterState(checkpoint);
737:                             },
738:                             timer);
739: 
740:             FutureUtils.forward(
741:                     CompletableFuture.allOf(masterStatesComplete, coordinatorCheckpointsComplete),
