89:     private final JobID job;
90: 
91:     /** The ID (logical timestamp) of the checkpoint. */
92:     private final long checkpointID;
93: 
94:     /** The timestamp when the checkpoint was triggered. */
95:     private final long timestamp;
96: 
97:     /** The timestamp when the checkpoint was completed. */
98:     private final long completionTimestamp;
99: 
100:     /** States of the different operator groups belonging to this checkpoint. */
101:     private final Map<OperatorID, OperatorState> operatorStates;
102: 
103:     /** Properties of this checkpoint. Might change during recovery. */
104:     private final CheckpointProperties props;
105: 
106:     /**
107:      * Properties of this checkpoint as they were during checkpoint creation. Might be null for
108:      * older versions.
109:      */
110:     @Nullable private final CheckpointProperties restoredProps;
111: 
112:     /** States that were created by a hook on the master (in the checkpoint coordinator). */
113:     private final Collection<MasterState> masterHookStates;
114: 
115:     /** The location where the checkpoint is stored. */
116:     private final CompletedCheckpointStorageLocation storageLocation;
117: 
118:     /** The state handle to the externalized meta data. */
119:     private final StreamStateHandle metadataHandle;
120: 
121:     /** External pointer to the completed checkpoint (for example file path). */
122:     private final String externalPointer;
