1201:      * a pending checkpoint.
1202:      *
1203:      * @param message Checkpoint ack from the task manager
1204:      * @param taskManagerLocationInfo The location of the acknowledge checkpoint message's sender
1205:      * @return Flag indicating whether the ack'd checkpoint was associated with a pending
1206:      *     checkpoint.
1207:      * @throws CheckpointException If the checkpoint cannot be added to the completed checkpoint
1208:      *     store.
1209:      */
1210:     public boolean receiveAcknowledgeMessage(
1211:             AcknowledgeCheckpoint message, String taskManagerLocationInfo)
1212:             throws CheckpointException {
1213:         if (shutdown || message == null) {
1214:             return false;
1215:         }
1216: 
1217:         if (!job.equals(message.getJob())) {
1218:             LOG.error(
1219:                     "Received wrong AcknowledgeCheckpoint message for job {} from {} : {}",
1220:                     job,
1221:                     taskManagerLocationInfo,
1222:                     message);
1223:             return false;
1224:         }
1225: 
1226:         final long checkpointId = message.getCheckpointId();
1227: 
1228:         synchronized (lock) {
1229:             // we need to check inside the lock for being shutdown as well, otherwise we
1230:             // get races and invalid error log messages
1231:             if (shutdown) {
1232:                 return false;
1233:             }
1234: 
1235:             final PendingCheckpoint checkpoint = pendingCheckpoints.get(checkpointId);
1236: 
1237:             if (message.getSubtaskState() != null) {
1238:                 // Register shared state regardless of checkpoint state and task ACK state.
1239:                 // This way, shared state is
1240:                 // 1. kept if the message is late or state will be used by the task otherwise
1241:                 // 2. removed eventually upon checkpoint subsumption (or job cancellation)
1242:                 // Do not register savepoints' shared state, as Flink is not in charge of
1243:                 // savepoints' lifecycle
1244:                 if (checkpoint == null || !checkpoint.getProps().isSavepoint()) {
1245:                     message.getSubtaskState()
1246:                             .registerSharedStates(
1247:                                     completedCheckpointStore.getSharedStateRegistry(),
1248:                                     checkpointId);
1249:                 }
1250:             }
1251: 
1252:             if (checkpoint != null && !checkpoint.isDisposed()) {
1253: 
1254:                 switch (checkpoint.acknowledgeTask(
1255:                         message.getTaskExecutionId(),
1256:                         message.getSubtaskState(),
1257:                         message.getCheckpointMetrics())) {
1258:                     case SUCCESS:
1259:                         LOG.debug(
1260:                                 "Received acknowledge message for checkpoint {} from task {} of job {} at {}.",
1261:                                 checkpointId,
1262:                                 message.getTaskExecutionId(),
1263:                                 message.getJob(),
1264:                                 taskManagerLocationInfo);
1265: 
1266:                         if (checkpoint.isFullyAcknowledged()) {
1267:                             completePendingCheckpoint(checkpoint);
1268:                         }
1269:                         break;
1270:                     case DUPLICATE:
1271:                         LOG.debug(
1272:                                 "Received a duplicate acknowledge message for checkpoint {}, task {}, job {}, location {}.",
1273:                                 message.getCheckpointId(),
1274:                                 message.getTaskExecutionId(),
1275:                                 message.getJob(),
1276:                                 taskManagerLocationInfo);
1277:                         break;
1278:                     case UNKNOWN:
1279:                         LOG.warn(
1280:                                 "Could not acknowledge the checkpoint {} for task {} of job {} at {}, "
1281:                                         + "because the task's execution attempt id was unknown. Discarding "
1282:                                         + "the state handle to avoid lingering state.",
1283:                                 message.getCheckpointId(),
1284:                                 message.getTaskExecutionId(),
1285:                                 message.getJob(),
1286:                                 taskManagerLocationInfo);
1287: 
1288:                         discardSubtaskState(
1289:                                 message.getJob(),
1290:                                 message.getTaskExecutionId(),
1291:                                 message.getCheckpointId(),
1292:                                 message.getSubtaskState());
1293: 
1294:                         break;
1295:                     case DISCARDED:
1296:                         LOG.warn(
1297:                                 "Could not acknowledge the checkpoint {} for task {} of job {} at {}, "
1298:                                         + "because the pending checkpoint had been discarded. Discarding the "
1299:                                         + "state handle tp avoid lingering state.",
1300:                                 message.getCheckpointId(),
