879:     private CheckpointStorageLocation initializeCheckpointLocation(
880:             long checkpointID,
881:             CheckpointProperties props,
882:             @Nullable String externalSavepointLocation,
883:             boolean initializeBaseLocations)
884:             throws Exception {
885:         final CheckpointStorageLocation checkpointStorageLocation;
886:         if (props.isSavepoint()) {
887:             checkpointStorageLocation =
888:                     checkpointStorageView.initializeLocationForSavepoint(
889:                             checkpointID, externalSavepointLocation);
890:         } else {
891:             if (initializeBaseLocations) {
892:                 checkpointStorageView.initializeBaseLocationsForCheckpoint();
893:             }
894:             checkpointStorageLocation =
895:                     checkpointStorageView.initializeLocationForCheckpoint(checkpointID);
896:         }
897: 
898:         return checkpointStorageLocation;
899:     }
