{"content":"1360:      * <p>Important: This method should only be called in the checkpoint lock scope.
1361:      *
1362:      * @param pendingCheckpoint to complete
1363:      * @throws CheckpointException if the completion failed
1364:      */
1365:     private void completePendingCheckpoint(PendingCheckpoint pendingCheckpoint)
1366:             throws CheckpointException {
1367:         final long checkpointId = pendingCheckpoint.getCheckpointID();
1368:         final CompletedCheckpoint completedCheckpoint;
1369:         final CompletedCheckpoint lastSubsumed;
1370:         final CheckpointProperties props = pendingCheckpoint.getProps();
1371: 
1372:         completedCheckpointStore.getSharedStateRegistry().checkpointCompleted(checkpointId);
1373: 
1374:         try {
1375:             completedCheckpoint = finalizeCheckpoint(pendingCheckpoint);
1376: 
1377:             // the pending checkpoint must be discarded after the finalization
1378:             Preconditions.checkState(pendingCheckpoint.isDisposed() && completedCheckpoint != null);
1379: 
1380:             if (!props.isSavepoint()) {
1381:                 lastSubsumed =
1382:                         addCompletedCheckpointToStoreAndSubsumeOldest(
1383:                                 checkpointId, completedCheckpoint, pendingCheckpoint);
1384:             } else {
1385:                 lastSubsumed = null;
1386:             }
1387: 
1388:             reportCompletedCheckpoint(completedCheckpoint);
1389:             pendingCheckpoint.getCompletionFuture().complete(completedCheckpoint);
1390:         } catch (Exception exception) {
1391:             // For robustness reasons, we need catch exception and try marking the checkpoint
1392:             // completed.
1393:             pendingCheckpoint.getCompletionFuture().completeExceptionally(exception);
1394:             throw exception;
1395:         } finally {
1396:             pendingCheckpoints.remove(checkpointId);
1397:             scheduleTriggerRequest();
1398:         }
1399: 
1400:         cleanupAfterCompletedCheckpoint(
1401:                 pendingCheckpoint, checkpointId, completedCheckpoint, lastSubsumed, props);
1402:     }
