1404:     private void reportCompletedCheckpoint(CompletedCheckpoint completedCheckpoint) {
1405:         failureManager.handleCheckpointSuccess(completedCheckpoint.getCheckpointID());
1406:         CompletedCheckpointStats completedCheckpointStats = completedCheckpoint.getStatistic();
1407:         if (completedCheckpointStats != null) {
1408:             LOG.trace(
1409:                     "Checkpoint {} size: {}Kb, duration: {}ms",
1410:                     completedCheckpoint.getCheckpointID(),
1411:                     completedCheckpointStats.getStateSize() == 0
1412:                             ? 0
1413:                             : completedCheckpointStats.getStateSize() / 1024,
1414:                     completedCheckpointStats.getEndToEndDuration());
1415:             // Finalize the statsCallback and give the completed checkpoint a
1416:             // callback for discards.
1417:             statsTracker.reportCompletedCheckpoint(completedCheckpointStats);
1418:         }
1419:     }
